@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classFontColor #333333
skinparam interfaceBackgroundColor #F5F5F5
skinparam interfaceBorderColor #333333
skinparam interfaceFontColor #333333
skinparam stereotypeCBackgroundColor #E0E0E0
skinparam stereotypeCBorderColor #333333
skinparam stereotypeCFontColor #333333
skinparam stereotypeIBackgroundColor #E0E0E0
skinparam stereotypeIBorderColor #333333
skinparam stereotypeIFontColor #333333
skinparam stereotypeABackgroundColor #E0E0E0
skinparam stereotypeABorderColor #333333
skinparam stereotypeAFontColor #333333
skinparam linetype ortho

class Transaction <<abstract>> {
    + Execute()
}

class DepositTransaction {
}

class WithdrawalTransaction {
}

class TransferTransaction {
}

interface DepositUI {
    + RequestDepositAmount()
}

interface WithdrawalUI {
    + RequestWithdrawalAmount()
}

interface TransferUI {
    + RequestTransferAmount()
}

interface UI {
    + RequestDepositAmount()
    + RequestWithdrawalAmount()
    + RequestTransferAmount()
}

Transaction <|-- DepositTransaction
Transaction <|-- WithdrawalTransaction
Transaction <|-- TransferTransaction

DepositTransaction ..> DepositUI
WithdrawalTransaction ..> WithdrawalUI
TransferTransaction ..> TransferUI

UI --|> DepositUI
UI --|> WithdrawalUI
UI --|> TransferUI

@enduml
